func (rcq *RepoConfigQuery) loadScmProvider(ctx context.Context, query *ScmProviderQuery, nodes []*RepoConfig, init func(*RepoConfig), assign func(*RepoConfig, *ScmProvider)) error {
	ids := make([]int, 0, len(nodes))
	nodeids := make(map[int][]*RepoConfig)
	for i := range nodes {
		if nodes[i].scm_provider_repo_configs == nil {
			continue
		}
		fk := *nodes[i].scm_provider_repo_configs
		if _, ok := nodeids[fk]; !ok {
			ids = append(ids, fk)
		}
		nodeids[fk] = append(nodeids[fk], nodes[i])
	}
	if len(ids) == 0 {
		return nil
	}
	query.Where(scmprovider.IDIn(ids...))
	neighbors, err := query.All(ctx)
	if err != nil {
		return err
	}
	for _, n := range neighbors {
		nodes, ok := nodeids[n.ID]
		if !ok {
			return fmt.Errorf(`unexpected foreign-key "scm_provider_repo_configs" returned %v`, n.ID)
		}
		for i := range nodes {
			assign(nodes[i], n)
		}
	}
	return nil
}
